const express = require('express');
const fs = require('fs');
const path = require('path');

const app = express();
const port = 3000;

// Load plugins from configuration files or environment variables
function loadPlugins() {
    const pluginConfig = process.env.PLUGINS || 'plugins.json';
    try {
        const plugins = JSON.parse(fs.readFileSync(pluginConfig, 'utf8'));
        return plugins.map(plugin => require(path.join(__dirname, plugin.path)));
    } catch (error) {
        console.error('Failed to load plugins:', error);
        return [];
    }
}

const plugins = loadPlugins();

// Middleware to apply plugins
app.use((req, res, next) => {
    for (const plugin of plugins) {
        if (plugin.requestHandler) {
            req = plugin.requestHandler(req);
        }
    }
    next();
});

// Example route
app.get('/', (req, res) => {
    res.send('Hello World!');
});

// Middleware to apply plugins after response is sent
app.use((req, res, next) => {
    for (const plugin of plugins) {
        if (plugin.responseHandler) {
            res = plugin.responseHandler(res);
        }
    }
    next();
});

app.listen(port, () => {
    console.log(`API Gateway listening at http://localhost:${port}`);
});